handlebars.registerHelper('equity_calendar', function(series) {
  if (!series || !series.fields) {
    return new handlebars.SafeString('<p style="color:#888;padding:16px">Sem dados de exchange_snapshots</p>');
  }

  var fields = series.fields;
  function findField(name) { return fields.find(function(f){return f.name===name;}); }

  var dayField  = findField('day');
  var pctField  = findField('pnl_pct');
  var usdtField = findField('pnl_usdt');

  if (!dayField) {
    return new handlebars.SafeString('<p style="color:#888;padding:16px">Campo day não encontrado</p>');
  }

  // GrafanaVector (.get) or plain array
  function toArr(f) {
    if (!f) return [];
    var v = f.values;
    if (Array.isArray(v)) return v;
    if (v && typeof v.get === 'function') {
      var a = []; for (var i=0; i<v.length; i++) a.push(v.get(i)); return a;
    }
    return Array.from(v || []);
  }

  var days  = toArr(dayField);
  var pcts  = toArr(pctField);
  var usdts = toArr(usdtField);

  var dayMap = {};
  for (var i=0; i<days.length; i++) {
    var dv = days[i];
    var ds = typeof dv === 'string' ? dv.slice(0,10)
           : dv instanceof Date      ? dv.toISOString().slice(0,10)
           : String(dv).slice(0,10);
    dayMap[ds] = { pct: parseFloat(pcts[i]||0), usdt: parseFloat(usdts[i]||0) };
  }

  function getColor(pct) {
    if (pct === null || pct === undefined) return 'rgba(255,255,255,0.04)';
    if (pct >  1.0) return '#1a7a1a';
    if (pct >  0.3) return '#2a8f2a';
    if (pct >  0.0) return '#4aab4a';
    if (pct === 0)  return 'rgba(255,255,255,0.06)';
    if (pct > -0.3) return '#ab4a4a';
    if (pct > -1.0) return '#8f2a2a';
    return '#7a1a1a';
  }

  var today = new Date();
  var mNames = ['Janeiro','Fevereiro','Março','Abril','Maio','Junho',
                'Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'];

  function pad(n) { return String(n).padStart(2,'0'); }

  function renderMonth(year, month) {
    var first = new Date(year, month, 1);
    var last  = new Date(year, month+1, 0);
    var startDow = first.getDay(); // 0=Dom
    var html = '<div style="min-width:240px">';
    html += '<div style="font-weight:700;color:#e0e0e0;text-align:center;margin-bottom:8px;font-size:13px">'
          + mNames[month] + ' ' + year + '</div>';
    html += '<div style="display:grid;grid-template-columns:repeat(7,34px);gap:2px">';
    ['D','S','T','Q','Q','S','S'].forEach(function(d) {
      html += '<div style="text-align:center;color:#555;font-size:10px;padding:2px 0">' + d + '</div>';
    });
    for (var e=0; e<startDow; e++) html += '<div></div>';
    for (var d=1; d<=last.getDate(); d++) {
      var ds = year+'-'+pad(month+1)+'-'+pad(d);
      var info = dayMap[ds];
      var isToday = (today.getFullYear()===year && today.getMonth()===month && today.getDate()===d);
      var bg = info ? getColor(info.pct) : 'rgba(255,255,255,0.03)';
      var border = isToday ? '1.5px solid #ffd700' : '1px solid rgba(255,255,255,0.06)';
      var title = info ? ds+': '+(info.pct>=0?'+':'')+info.pct.toFixed(3)+'% ($'+(info.usdt>=0?'+':'')+info.usdt.toFixed(2)+')' : ds;
      var sub = info ? '<div style="font-size:8px;color:rgba(255,255,255,0.75);line-height:1.1;margin-top:1px">'
                     + (info.pct>=0?'+':'')+info.pct.toFixed(2)+'%</div>' : '';
      html += '<div title="'+title+'" style="background:'+bg+';border:'+border+';border-radius:3px;padding:3px 1px;text-align:center;cursor:default">'
            + '<div style="font-size:10px;color:rgba(255,255,255,'+(isToday?'1':'0.8')+');font-weight:'+(isToday?700:400)+'">'+d+'</div>'
            + sub + '</div>';
    }
    html += '</div></div>';
    return html;
  }

  var months = [];
  for (var mi=2; mi>=0; mi--) {
    var md = new Date(today.getFullYear(), today.getMonth()-mi, 1);
    months.push(renderMonth(md.getFullYear(), md.getMonth()));
  }

  var legend = [
    ['#1a7a1a','>+1%'], ['#2a8f2a','+0.3 a +1%'], ['#4aab4a','0 a +0.3%'],
    ['rgba(255,255,255,0.06)','sem dado'],
    ['#ab4a4a','0 a -0.3%'], ['#8f2a2a','-0.3 a -1%'], ['#7a1a1a','<-1%']
  ].map(function(l) {
    return '<span style="background:'+l[0]+';border-radius:3px;padding:2px 7px;color:rgba(255,255,255,0.9);font-size:11px">'+l[1]+'</span>';
  }).join('');

  return new handlebars.SafeString(
    '<div style="padding:16px;font-family:Inter,sans-serif">'
    + '<div style="font-size:14px;font-weight:700;color:#FF9830;margin-bottom:4px">📅 PnL Diário — Equity vs Exchange</div>'
    + '<div style="color:#8e8ea0;font-size:11px;margin-bottom:16px">Variação patrimônio total (USDT livre + BTC a mercado) — equivalente ao indicador "PnL do dia" da KuCoin</div>'
    + '<div style="display:flex;gap:20px;flex-wrap:wrap">' + months.join('') + '</div>'
    + '<div style="margin-top:14px;display:flex;gap:6px;align-items:center;flex-wrap:wrap">'
    + '<span style="color:#8e8ea0;font-size:11px;margin-right:4px">Legenda:</span>' + legend
    + '</div></div>'
  );
});
